div.script:
// 
(async function() {
  const gameUrl = "https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/BPLPremium.html";
  const baseUrl = "https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/";
  const frame = document.getElementById('game-loader');

  try {
    const response = await fetch(gameUrl);
    if (!response.ok) throw new Error("Fetch failed");
    const html = await response.text();

    // Access the iframe's document
    const fdoc = frame.contentWindow.document;

    // This tells the game to look at jsDelivr for its assets
    const baseTag = `<base href="${baseUrl}">`;

    // We 'write' the content. This is better than srcdoc for Safari
    // as it helps maintain a more stable environment.
    fdoc.open();
    fdoc.write(baseTag + html);
    fdoc.close();

  } catch (err) {
    console.error("BPL Loader Error:", err);
    document.getElementById('bpl-container').innerHTML = 
      `<div style="color:white; font-family:sans-serif; text-align:center; padding-top:20%;">
        Error: ${err.message}<br/>Check network or link.
      </div>`;
  }
})();
//
